  "2026-05-16":"uploaded","2026-05-17":"uploaded","2026-05-18":"uploaded","2026-05-19":"uploaded","2026-05-20":"uploaded",
  "2026-05-21":"uploaded","2026-05-22":"uploaded","2026-05-23":"stopped","2026-05-24":"uploaded","2026-05-25":"uploaded",
