function getWorkerResumeList(w){
  if(!w)return [];

  const projectOrgMap={
    "虹桥地下综合管廊项目":{sub:"上海隧道",branch:"轨交分公司"},
    "北横通道改造项目":{sub:"上海隧道",branch:"轨交分公司"},
    "华东智慧产业园一期":{sub:"上海隧道",branch:"轨交分公司"},
    "深圳前海市政配套项目":{sub:"城建国际",branch:"新加坡分公司"},
    "湾区金融中心项目":{sub:"城建国际",branch:"新加坡分公司"},
    "济南地铁车站主体项目":{sub:"市政集团",branch:"第一建筑"},
    "北方数据中心项目":{sub:"市政集团",branch:"第一建筑"}
  };

  const normalize=(r={})=>{
    const org=projectOrgMap[r.project] || {};
    return {
      project:r.project || "--",
      sub:r.sub || r.subCompany || org.sub || w.sub || "--",
      branch:r.branch || org.branch || w.branch || "--",
      unit:r.unit || r.currentUnit || w.unit || "--",
      team:r.team || r.currentTeam || w.team || "--",
      type:r.type || w.type || "--",
      job:r.job || r.position || w.job || "--",
      inDate:r.inDate || r.startDate || "--",
      outDate:r.outDate || r.endDate || "--"
    };
  };

  const current=normalize({
    project:w.project,
    sub:w.sub,
    branch:w.branch,
    unit:w.unit,
    team:w.team,
    type:w.type,
    job:w.job,
    inDate:w.inDate,
    outDate:w.outDate || "--"
  });

  const historyMap={
    1:[
      {
        project:"虹桥地下综合管廊项目",
        sub:"上海隧道",
        branch:"轨交分公司",
        unit:"四川宏安劳务有限公司",
        team:"钢筋二班",
        type:"劳务工人",
        job:"钢筋工",
        inDate:"2024-03-10",
        outDate:"2025-01-20"
      },
      {
        project:"北横通道改造项目",
        sub:"上海隧道",
        branch:"轨交分公司",
        unit:"四川宏安劳务有限公司",
        team:"焊工一班",
        type:"特种作业人员",
        job:"焊工",
        inDate:"2025-03-08",
        outDate:"2025-12-30"
      }
    ],
    2:[
      {
        project:"深圳前海市政配套项目",
        sub:"城建国际",
        branch:"新加坡分公司",
        unit:"豫达建筑劳务有限公司",
        team:"木工二班",
        type:"劳务工人",
        job:"木工",
        inDate:"2024-06-12",
        outDate:"2025-05-18"
      }
    ],
    3:[
      {
        project:"济南地铁车站主体项目",
        sub:"市政集团",
        branch:"第一建筑",
        unit:"鲁建劳务有限公司",
        team:"架子工一班",
        type:"特种作业人员",
        job:"架子工",
        inDate:"2023-09-01",
        outDate:"2024-10-30"
      }
    ]
  };

  const rawHistory=(w.workHistory || w.resume || historyMap[w.id] || []).map(normalize);
  return [...rawHistory, current];
}

